import{_ as i,o as a,c as e,a2 as n}from"./chunks/framework.BflysNKA.js";const k=JSON.parse('{"title":"接入 Codex","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/codex.md","filePath":"deploy/codex.md","lastUpdated":1778663407000}'),l={name:"deploy/codex.md"};function p(t,s,o,h,r,d){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="接入-codex" tabindex="-1">接入 Codex <a class="header-anchor" href="#接入-codex" aria-label="Permalink to &quot;接入 Codex&quot;">​</a></h1><p>Codex 更像一套长期使用的本地工作流：默认模型、网关地址和行为偏好通常写在 <code>config.toml</code>，真正的 Key 再交给环境变量。</p><p>环境未配置时，先完成 <a href="/beginner/windows">Windows 快速接入</a> 或 <a href="/beginner/macos">macOS 快速接入</a>。</p><p>和 Claude Code 不同，Codex 不是“只写两个环境变量就完事”的工具。<br> 它更适合把长期默认值固定下来，这样你换项目、重开终端或切模型时，不用每次都从头再配。</p><p>Codex 这里最容易记错的一点是 Base URL。<br> 它走的是 OpenAI 兼容接口，所以这里要写：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不是根地址。<br> Claude Code、Gemini CLI、Cherry Studio 这些工具各自对地址的要求不完全一样，Codex 这一页只记住一条：<strong>Codex 的 <code>base_url</code> 要带 <code>/v1</code></strong>。</p><h2 id="开始前先检查" tabindex="-1">开始前先检查 <a class="header-anchor" href="#开始前先检查" aria-label="Permalink to &quot;开始前先检查&quot;">​</a></h2><p>这些命令用于确认本机能安装和运行 Codex：<code>node</code> 和 <code>npm</code> 用来安装 CLI，<code>git</code> 用来读取项目仓库，npm registry 用来判断下载源是否适合国内网络。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>npm 下载慢时，先切镜像源：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="为什么更推荐-config-toml-环境变量" tabindex="-1">为什么更推荐 <code>config.toml</code> + 环境变量 <a class="header-anchor" href="#为什么更推荐-config-toml-环境变量" aria-label="Permalink to &quot;为什么更推荐 \`config.toml\` + 环境变量&quot;">​</a></h2><p>OpenAI 官方当前文档里，自定义 Provider 更稳的写法是：</p><ul><li><code>config.toml</code> 负责说明模型、网关和协议</li><li>环境变量负责提供 API Key</li></ul><p>这样做有三个好处：</p><ol><li>模型和网关配置能稳定保留在 Codex 的正式配置里</li><li>Key 不用手改缓存文件，轮换更方便</li><li>出问题时更容易判断是配置层问题，还是鉴权层问题</li></ol><p>如果你以前用过官方登录流程，<code>~/.codex/auth.json</code> 可能已经存在。<br> 那是 Codex 自己的认证缓存，不代表接入 小蓝中转站 时还要继续手动编辑它。当前这套接法不依赖手改 <code>auth.json</code>。</p><h2 id="方式一-使用-cc-switch-图形界面" tabindex="-1">方式一：使用 CC-Switch（图形界面） <a class="header-anchor" href="#方式一-使用-cc-switch-图形界面" aria-label="Permalink to &quot;方式一：使用 CC-Switch（图形界面）&quot;">​</a></h2><p>如果你已经在用 <a href="/tools/cc-switch">CC-Switch</a>，可以通过图形界面写入 Codex 配置：</p><p>这种方式适合不想手动编辑配置文件的用户。保存后仍然建议启动 Codex 做一次最小测试。</p><ol><li>打开 <strong>CC-Switch</strong>，进入 <strong>Codex</strong> 面板。</li><li>创建配置档案： <ul><li><strong>Base URL</strong>：<code>https://xiaolan1.cn/v1</code></li><li><strong>API Key</strong>：填入 小蓝中转站控制台创建的 Key</li><li><strong>Model</strong>：从<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>复制模型名</li></ul></li><li>保存并应用。</li><li>重启终端中的 Codex。</li></ol><h2 id="模型怎么选" tabindex="-1">模型怎么选 <a class="header-anchor" href="#模型怎么选" aria-label="Permalink to &quot;模型怎么选&quot;">​</a></h2><p>Codex 配置里的 <code>model</code> 要从模型广场复制。第一次测试可以先选轻量模型，确认配置文件和 Key 正常；真实代码任务再切换到支持 Responses / OpenAI 兼容调用、代码能力更强的模型。</p><p>第一次接入时，建议把这三个概念分开看：</p><ul><li><strong>Key 分组</strong>：决定这把 Key 能走哪些可用渠道</li><li><strong>模型权限</strong>：决定这把 Key 能调用哪些模型</li><li><strong><code>config.toml</code> 里的 <code>model</code></strong>：决定 Codex 当前默认请求哪个模型</li></ul><p>推荐顺序：</p><ol><li>在<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>找到目标模型。</li><li>确认 Key 所选分组能使用该模型。</li><li>复制完整模型名。</li><li>写入 <code>config.toml</code> 的 <code>model</code> 字段。</li></ol><p>如果启动后提示模型不存在，先检查 <code>model</code> 字段是否完整，再检查 Key 的分组和模型权限。</p><h2 id="方式二-手动配置文件" tabindex="-1">方式二：手动配置文件 <a class="header-anchor" href="#方式二-手动配置文件" aria-label="Permalink to &quot;方式二：手动配置文件&quot;">​</a></h2><p>按下面步骤手动创建 Codex 配置。<br> 手动方式的好处是每一层都看得见：你知道地址写在哪、模型写在哪、Key 从哪里读。</p><h3 id="_1-安装-codex-cli" tabindex="-1">1. 安装 Codex CLI <a class="header-anchor" href="#_1-安装-codex-cli" aria-label="Permalink to &quot;1. 安装 Codex CLI&quot;">​</a></h3><p>Codex CLI 官方常见安装方式有三种：</p><ol><li>npm 全局安装</li><li>Homebrew 安装</li><li>GitHub Release 二进制压缩包</li></ol><p>如果你已经装好 Node.js，优先继续用 npm；如果你平时主要用 Homebrew 管理命令行工具，可以直接走 Homebrew。</p><p>官方入口：</p><ul><li>官方文档：<a href="https://developers.openai.com/codex/cli" target="_blank" rel="noreferrer">https://developers.openai.com/codex/cli</a></li><li>官方配置文档：<a href="https://developers.openai.com/codex/config" target="_blank" rel="noreferrer">https://developers.openai.com/codex/config</a></li><li>GitHub 发布页：<a href="https://github.com/openai/codex/releases/latest" target="_blank" rel="noreferrer">https://github.com/openai/codex/releases/latest</a></li></ul><p>方式一：npm</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @openai/codex@latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>macOS 上用浏览器安装 Node.js 的机器，执行这一步时更常见的写法是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @openai/codex@latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>终端出现钥匙图标或 <code>Password:</code> 提示后，密码不会显示任何字符，直接输入完成后按回车即可。</p><p>方式二：Homebrew</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> codex</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>方式三：GitHub Release</p><p>不想通过 npm 或 Homebrew 安装时，再去官方发布页下载对应系统压缩包。</p><h3 id="_2-创建配置目录" tabindex="-1">2. 创建配置目录 <a class="header-anchor" href="#_2-创建配置目录" aria-label="Permalink to &quot;2. 创建配置目录&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.codex</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.codex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3-编写-config-toml" tabindex="-1">3. 编写 <code>config.toml</code> <a class="header-anchor" href="#_3-编写-config-toml" aria-label="Permalink to &quot;3. 编写 \`config.toml\`&quot;">​</a></h3><p>在 <code>~/.codex</code> 目录下新建 <code>config.toml</code>，写入以下内容。将 <code>model</code> 字段替换为模型广场复制的模型名。</p><div class="language-toml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 默认使用这组自定义 Provider</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">model_provider = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;xiaolan&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 改成模型广场复制的真实模型名</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;replace-with-model-from-pricing&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 复杂代码任务通常比 low 更稳</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">model_reasoning_effort = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;high&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 需要执行高风险操作时先询问</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;on-request&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 允许在当前项目目录里读写文件</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">sandbox_mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;workspace-write&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">model_providers</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">xiaolan</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只是本地显示名称，方便你自己识别</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;小蓝中转站&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Codex 走的是 OpenAI 兼容接口，所以地址要带 /v1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">base_url = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;https://xiaolan1.cn/v1&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Codex 自定义 Provider 走 Responses API 协议</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">wire_api = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;responses&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 告诉 Codex：真正的 Key 去环境变量里取</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">env_key = </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;小蓝中转站_API_KEY&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><p>这几项分别负责的事情可以这样理解：</p><ul><li><code>model_provider = &quot;xiaolan&quot;</code>：告诉 Codex 默认使用这一组自定义 Provider</li><li><code>model = &quot;...&quot;</code>：告诉 Codex 默认请求哪个模型</li><li><code>base_url = &quot;https://xiaolan1.cn/v1&quot;</code>：告诉 Codex 请求发往哪个网关地址</li><li><code>wire_api = &quot;responses&quot;</code>：告诉 Codex 按哪种接口协议和网关通信</li><li><code>env_key = &quot;小蓝中转站_API_KEY&quot;</code>：告诉 Codex 去哪个环境变量里读 Key</li></ul><p>这份配置里最关键的是三项：</p><ul><li><code>base_url = &quot;https://xiaolan1.cn/v1&quot;</code></li><li><code>wire_api = &quot;responses&quot;</code></li><li><code>env_key = &quot;小蓝中转站_API_KEY&quot;</code></li></ul><p>前两项决定请求会不会正确发到 小蓝中转站；最后一项决定 Codex 去哪里找你的 Key。</p><h3 id="_4-写入-xiaolan-api-key" tabindex="-1">4. 写入 <code>小蓝中转站_API_KEY</code> <a class="header-anchor" href="#_4-写入-xiaolan-api-key" aria-label="Permalink to &quot;4. 写入 \`小蓝中转站_API_KEY\`&quot;">​</a></h3><h4 id="macos-linux" tabindex="-1">macOS / Linux <a class="header-anchor" href="#macos-linux" aria-label="Permalink to &quot;macOS / Linux&quot;">​</a></h4><p>把下面这一行追加到 <code>~/.zshrc</code>、<code>~/.bashrc</code> 或你当前 shell 的配置文件里：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> 小蓝中转站_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;sk-你的专属Key&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>保存后执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.zshrc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你用的是 Bash，把 <code>~/.zshrc</code> 换成对应的 <code>~/.bashrc</code> 或 <code>~/.bash_profile</code>。</p><h4 id="windows-powershell" tabindex="-1">Windows PowerShell <a class="header-anchor" href="#windows-powershell" aria-label="Permalink to &quot;Windows PowerShell&quot;">​</a></h4><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;小蓝中转站_API_KEY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;sk-你的专属Key&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>写完后，完全关闭当前终端，再重新打开一个新窗口。</p><h3 id="_5-启动-codex" tabindex="-1">5. 启动 Codex <a class="header-anchor" href="#_5-启动-codex" aria-label="Permalink to &quot;5. 启动 Codex&quot;">​</a></h3><p>为了避免在根目录产生不必要的文件，建议建个测试目录启动：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/codex-test</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/codex-test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果你在 Windows PowerShell 里测试，对应写法可以换成：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">mkdir $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">USERPROFILE\\codex</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">cd $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">USERPROFILE\\codex</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">codex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="配置文件放哪里" tabindex="-1">配置文件放哪里 <a class="header-anchor" href="#配置文件放哪里" aria-label="Permalink to &quot;配置文件放哪里&quot;">​</a></h2><p>最常见的是两层：</p><ul><li>用户级默认配置：<code>~/.codex/config.toml</code></li><li>项目级覆盖配置：项目根目录 <code>.codex/config.toml</code></li></ul><p>OpenAI 官方当前文档把项目级 <code>.codex/config.toml</code> 作为覆盖层。<br> 也就是说，你完全可以先把 小蓝中转站、默认模型和常用行为写进用户级配置；等某个仓库想单独限制模型时，再在那个仓库里额外补一份项目级配置。</p><p>不确定主目录时：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $HOME</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Windows PowerShell：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">USERPROFILE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="最小验证" tabindex="-1">最小验证 <a class="header-anchor" href="#最小验证" aria-label="Permalink to &quot;最小验证&quot;">​</a></h2><p>进入一个测试目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/codex-xiaolan-test</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/codex-xiaolan-test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>进入后发送：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>创建一个 hello.js，打印 hello xiaolan。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第一次不急着让它直接改大型仓库。先确认四件事：</p><ol><li><code>codex</code> 能正常启动</li><li>不会跳回官方登录流程</li><li>能正常返回回复</li><li>当前模型确实是你在 <code>config.toml</code> 里写的那一个</li></ol><p>这四件事都成立，再切到真实项目目录会更稳。</p><p>如果这一条测试已经成功，后面再遇到问题，范围通常就能明显缩小到：</p><ul><li>当前项目目录里是否有另一份 <code>.codex/config.toml</code></li><li>当前终端有没有读到新的 <code>小蓝中转站_API_KEY</code></li><li>当前切换的模型是不是超出了这把 Key 的分组或模型权限</li></ul><h2 id="排障" tabindex="-1">排障 <a class="header-anchor" href="#排障" aria-label="Permalink to &quot;排障&quot;">​</a></h2><ul><li><strong>流量似乎没有走网关？</strong><br> 回去检查 <code>config.toml</code> 里的 <code>[model_providers.xiaolan]</code>，确认 <code>base_url</code> 和 <code>wire_api</code> 没有拼写错误。</li><li><strong>提示 API Key 无效或未提供？</strong><br> 先检查 <code>echo $小蓝中转站_API_KEY</code> 或 <code>echo $env:小蓝中转站_API_KEY</code> 是否真有值。很多问题不是 Codex 不认 Key，而是当前终端根本没拿到这个变量。</li><li><strong>响应慢？</strong><br> 先在配置里换个轻量模型试一次，排查是模型排队、上下文过大，还是本地网络问题。</li><li><strong>TOML 解析失败？</strong><br> 检查等号、引号和段落名。<code>[model_providers.xiaolan]</code> 必须使用英文方括号，不要漏掉下划线。</li><li><strong>改了配置还不生效？</strong><br> 关闭所有 Codex 进程，重新打开终端。再确认当前项目目录里是不是还有另一份 <code>.codex/config.toml</code> 把用户级配置覆盖了。</li><li><strong>Base URL 写成根地址会怎样？</strong><br> Codex 走的是 OpenAI 兼容接口，少了 <code>/v1</code> 时，请求路径通常不会按预期拼接，表现往往像接口异常、请求失败或始终进不了正常对话。</li><li><strong>以前配过官方账号，现在担心冲突？</strong><br> 先不要急着删 <code>auth.json</code>。当前这套 小蓝中转站 接法主要看 <code>config.toml</code> 和 <code>小蓝中转站_API_KEY</code>，优先把这两层核对清楚。</li></ul>`,91)])])}const b=i(l,[["render",p]]);export{k as __pageData,b as default};
